import { useState } from 'react';

// ==========================================
// MAIN APP COMPONENT
// ==========================================
function App() {
  const [currentPage, setCurrentPage] = useState('login');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userRole, setUserRole] = useState(null);
  const [userData, setUserData] = useState(null);

  const handleLoginSuccess = (role) => {
    setIsAuthenticated(true);
    setUserRole(role);
    setUserData({ role, email: 'user@example.com' });
  };

  const handleSignupSuccess = (data) => {
    setIsAuthenticated(true);
    setUserRole(data.role);
    setUserData(data);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserRole(null);
    setUserData(null);
    setCurrentPage('login');
  };

  if (!isAuthenticated) {
    return currentPage === 'login' ? (
      <LoginPage
        onLoginSuccess={handleLoginSuccess}
        goToSignup={() => setCurrentPage('signup')}
      />
    ) : (
      <SignupPage
        onSignupSuccess={handleSignupSuccess}
        goToLogin={() => setCurrentPage('login')}
      />
    );
  }

  if (userRole === 'admin') {
    return <AdminDashboard userData={userData} onLogout={handleLogout} />;
  }

  if (userRole === 'technician') {
    return <TechnicianDashboard userData={userData} onLogout={handleLogout} />;
  }

  return <UserDashboard userData={userData} onLogout={handleLogout} />;
}

// ==========================================
// LOGIN PAGE
// ==========================================
function LoginPage({ onLoginSuccess, goToSignup }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = () => {
    if (!email || !password) {
      setError('Please fill all fields');
      return;
    }

    let role = 'user';
    if (email.includes('admin')) role = 'admin';
    if (email.includes('tech')) role = 'technician';

    onLoginSuccess(role);
  };

  return (
    <div style={styles.container}>
      <div style={styles.box}>
        <h2>Login</h2>
        <input style={styles.input} placeholder="Email" onChange={e => setEmail(e.target.value)} />
        <input style={styles.input} type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
        {error && <p style={styles.error}>{error}</p>}
        <button style={styles.button} onClick={handleLogin}>Login</button>
        <p onClick={goToSignup} style={styles.link}>Create account</p>
      </div>
    </div>
  );
}

// ==========================================
// SIGNUP PAGE
// ==========================================
function SignupPage({ onSignupSuccess, goToLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('user');

  return (
    <div style={styles.container}>
      <div style={styles.box}>
        <h2>Signup</h2>
        <input style={styles.input} placeholder="Email" onChange={e => setEmail(e.target.value)} />
        <input style={styles.input} type="password" placeholder="Password" onChange={e => setPassword(e.target.value)} />
        <select style={styles.input} onChange={e => setRole(e.target.value)}>
          <option value="user">User</option>
          <option value="technician">Technician</option>
          <option value="admin">Admin</option>
        </select>
        <button
          style={styles.button}
          onClick={() => onSignupSuccess({ email, role })}
        >
          Signup
        </button>
        <p onClick={goToLogin} style={styles.link}>Back to login</p>
      </div>
    </div>
  );
}

// ==========================================
// DASHBOARDS
// ==========================================
function AdminDashboard({ onLogout }) {
  return <Dashboard title="Admin Dashboard" onLogout={onLogout} />;
}

function TechnicianDashboard({ onLogout }) {
  return <Dashboard title="Technician Dashboard" onLogout={onLogout} />;
}

function UserDashboard({ onLogout }) {
  return <Dashboard title="User Dashboard" onLogout={onLogout} />;
}

function Dashboard({ title, onLogout }) {
  return (
    <div style={styles.container}>
      <div style={styles.box}>
        <h2>{title}</h2>
        <button style={styles.button} onClick={onLogout}>Logout</button>
      </div>
    </div>
  );
}

// ==========================================
// STYLES
// ==========================================
const styles = {
  container: {
    height: '100vh',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    background: '#f4f6f8'
  },
  box: {
    background: '#fff',
    padding: 30,
    borderRadius: 10,
    width: 300,
    textAlign: 'center'
  },
  input: {
    width: '100%',
    padding: 10,
    margin: '8px 0'
  },
  button: {
    width: '100%',
    padding: 10,
    marginTop: 10,
    background: '#2563eb',
    color: '#fff',
    border: 'none'
  },
  link: {
    marginTop: 10,
    color: '#2563eb',
    cursor: 'pointer'
  },
  error: {
    color: 'red'
  }
};

export default App;
